const TT = (moduleId, id, num, name, slug, tags, hookQ, hookI, blocks, rel, gaps, diff, svgStr, vaType) => ({
  trackKey: TRACK_KEY, moduleId, topicId: id, topicNumber: num, name, slug,
  metadata: { estimated_minutes: 50, difficulty: 4, prerequisites: [], tags },
  hook: { question: hookQ, insight: hookI },
  teaching: { blocks, visual_aid: { type: vaType, svg: svgStr, alt_text: `${name} architecture diagram.` } },
  interviewRelevance: rel, commonGaps: { gaps },
  prerequisites: [], estimatedMinutes: 50, difficulty: diff, xpReward: 80, visualizer: null,
});
const C = (section, heading, body) => ({ kind: "concept", section, heading, body });
const K = (section, heading, body) => ({ kind: "code", section, heading, body });
const G = (id, w, r, d) => ({ gap_id: id, what_students_get_wrong: w, remediation: r, detection_pattern: d });

const TOPICS = [
  // ───────────────────── PRICE-COMPARISON AGGREGATOR ───────────────────────
  TT("sysd_m12", "sysd_m12_t8", 8, "Design a Price-Comparison Aggregator", "design-price-aggregator",
    ["case-study", "aggregation", "entity-resolution", "freshness"],
    "You want to show shoppers the cheapest price for a TV across fifty retailers — but each retailer lists it with a different title, SKU, and page format, and prices change hourly. The hard part isn't displaying prices; it's knowing that '55\" OLED X900' on one site is the SAME product as 'Sony 55in OLED' on another. How do you build a price-comparison aggregator?",
    "INGEST prices from many sources (retailer APIs + web SCRAPING), then NORMALIZE and MATCH listings so the SAME product across different retailers is recognized as one (product matching / entity resolution — the hard part), store + index the matched products with their prices, and serve comparison + search; keep prices FRESH via prioritized re-crawling, handling source variety and breakage. Ingestion + product matching/normalization + freshness/serving are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: AGGREGATE product PRICES from many RETAILERS/sources, let users SEARCH a product and COMPARE its prices across sellers (find the cheapest), with up-to-date prices; product details, deals, history. Non-functional: DATA INGESTION from MANY heterogeneous sources (retailer APIs + web SCRAPING of sites you don't control), PRODUCT MATCHING/normalization (recognize the same product across sources), FRESHNESS (prices change — stale prices mislead users), SEARCH at scale, and resilience to source changes/breakage. Clarify scope: a price-comparison / shopping aggregator (Google Shopping / PriceGrabber style). The defining challenges: (1) INGESTING data from MANY heterogeneous SOURCES you don't control — some offer feeds/APIs, but many require WEB SCRAPING (parsing retailer pages), which is brittle (sites change layout, block scrapers) and varied; and (2) PRODUCT MATCHING / ENTITY RESOLUTION — the HARD part: the SAME physical product is listed by different retailers with DIFFERENT titles, SKUs, descriptions, and formats ('Sony 55\" OLED A90J' vs 'Sony Bravia XR-55A90J 55-inch'), so you must RECOGNIZE that these listings refer to the SAME product and group them — a fuzzy matching/entity-resolution problem (using identifiers like UPC/GTIN when available, plus title/attribute matching/ML) — without which 'comparison' is impossible; and (3) FRESHNESS — prices change frequently, so you must re-crawl/refresh to avoid showing stale prices. So the design centers on multi-source ingestion + product matching/normalization + freshness/serving."),
      K("estimation", "Capacity estimation (with numbers)",
        "Sources: many retailers -> APIs where available + web SCRAPING (brittle, varied) otherwise.\nProducts: millions of listings across sources -> match into canonical products (entity resolution).\nMatching: same product, different titles/SKUs per retailer -> fuzzy match (UPC/GTIN + attributes/ML).\nFreshness: prices change -> re-crawl periodically ; prioritize popular products (limited crawl budget).\nServe: search a product -> show its prices across retailers (compare) -> read-heavy, cached.\nTakeaway: ingest many sources + match/normalize products (the hard part) + keep prices fresh\n(prioritized re-crawl) + read-heavy compare/search serving."),
      C("hld", "High-level design",
        "INGESTION: collect product + price data from many SOURCES — retailer APIs/FEEDS where available, and WEB SCRAPING (crawl + parse retailer pages) where not — a fleet of source-specific ingesters/scrapers (resilient to site changes, respecting robots/rate limits). NORMALIZATION + PRODUCT MATCHING: incoming listings are NORMALIZED (clean titles, units, categories) and MATCHED — group listings that refer to the SAME product into a CANONICAL product (entity resolution): use strong identifiers (UPC/GTIN/MPN) when present, else fuzzy match on title + attributes + brand/model (and ML/embeddings for hard cases) — this is the crux, since comparison requires knowing different retailers' listings are the same item. The matched canonical products + their per-retailer prices are STORED and INDEXED (a search index over products + a store of prices per product per retailer). SERVING: users SEARCH a product and COMPARE prices across retailers (cheapest first), see deals/history — read-heavy, so cached. FRESHNESS: a crawl scheduler RE-FETCHES prices periodically, PRIORITIZING popular/volatile products (you can't re-crawl everything constantly — limited budget), to keep prices current. Trace it: scrape/ingest 50 retailers -> normalize + match the '55\" OLED' listings into one product -> store its 50 prices -> a user searches it -> show cheapest across retailers; re-crawl popular products hourly for fresh prices. Multi-source ingestion -> normalize + match products (entity resolution) -> store/index -> compare/search + prioritized re-crawl is the shape."),
      K("api", "API / flow",
        "ingest: per-source (retailer API/feed | web scraper) -> raw listings (title, SKU, price)\nnormalize + MATCH: group listings of the same product (UPC/GTIN | fuzzy title+attributes/ML)\n  -> canonical product + per-retailer prices (entity resolution)\nstore/index: canonical products (search index) + prices per product per retailer\nserve: search product -> compare prices across retailers (cheapest) ; cached (read-heavy)\nfreshness: crawl scheduler re-fetches prices, prioritizing popular/volatile products"),
      K("data_model", "Data model",
        "sources: retailers + ingestion method (API/feed | scraper) + parse rules\nlistings: raw per-retailer (title, SKU, price, url) -> matched to a canonical product\ncanonical products: deduped product + attributes (entity-resolution result)\nprices: per canonical product per retailer (current + history) -> compare\nsearch index: products (for search) ; crawl schedule (freshness, prioritized)"),
      C("deep_dive", "Deep dive: ingestion & product matching (entity resolution)",
        "The defining hard problem is MATCHING the same product across sources — entity resolution. INGESTION first: data comes from MANY heterogeneous sources — some retailers provide product FEEDS/APIs (structured, easy), but many require WEB SCRAPING (fetch + parse their pages to extract product + price), which is BRITTLE (page layouts change -> parsers break), VARIED (every site is different -> per-source parse logic), and adversarial (sites block scrapers, rate-limit) — so the ingestion layer is a fleet of source-specific, maintained scrapers/connectors handling this messiness (respecting robots.txt/rate limits, retrying, detecting breakage). THE MATCHING PROBLEM (the crux): the SAME physical product is listed by different retailers with DIFFERENT titles, SKUs, descriptions, images, and formats — 'Sony 55\" OLED A90J', 'Sony Bravia XR-55A90J', 'Sony A90J 55 inch OLED TV' all refer to ONE product — and price COMPARISON is impossible unless you RECOGNIZE these as the SAME product and group them into a CANONICAL product. This is ENTITY RESOLUTION / record linkage, the hard part: (1) when STRONG IDENTIFIERS exist (UPC/EAN/GTIN/MPN — universal product codes), matching is easy (same code = same product) — so use them when available; (2) otherwise, FUZZY MATCH on title + brand/model + attributes (specs) — normalize text, extract key attributes, and compute similarity, increasingly with ML/embeddings (semantic matching of product descriptions) to handle wording differences — accepting some uncertainty (false matches conflate different products; missed matches fragment a product across listings — both hurt comparison). NORMALIZATION (clean/standardize titles, units, categories, currencies) precedes matching. So robust multi-source ingestion (APIs + brittle scraping) + product matching/entity resolution (UPC/GTIN when available, else fuzzy/ML attribute matching) is the core interviewers probe — and naming entity resolution as THE hard part (not just 'store prices') is the key insight."),
      C("deep_dive", "Deep dive: freshness, serving & handling source change",
        "Around matching sit FRESHNESS, read-heavy SERVING, and resilience to source change. FRESHNESS: prices CHANGE frequently (sales, dynamic pricing, stock), and showing a STALE price misleads users (they click through to a different price — bad UX/trust) — so you must RE-CRAWL/refresh prices regularly; but you CANNOT re-fetch every product from every source constantly (a huge crawl/scraping budget, and you'd hammer/anger sources), so you PRIORITIZE: re-crawl POPULAR products and VOLATILE prices more often, long-tail less often — a scheduling/prioritization problem (limited crawl budget allocated by importance + change rate), the same freshness-vs-cost tension as a web crawler. Some sources push updates (feeds), reducing crawl need. SERVING (read-heavy): users search products and view comparisons far more than data changes, so the serving path is read-optimized — a SEARCH index over canonical products (find the product) + a fast store of per-retailer prices (show the comparison, cheapest first) — heavily CACHED (popular products), with price HISTORY and deal alerts as features. HANDLING SOURCE CHANGE/BREAKAGE: scrapers BREAK when retailer sites change layout (a constant operational reality) — so monitor ingestion health (detect when a source stops yielding data / yields garbage), alert, and fix parsers; also handle anti-scraping measures and source removal. DATA QUALITY: validate ingested prices (catch parse errors — a $0 or $1M price), dedupe, and reconcile conflicting data; accuracy matters (wrong prices erode trust). MONETIZATION (affiliate links) and click-through tracking are typical. So prioritized re-crawl for freshness (limited budget) + read-heavy cached compare/search serving + ingestion-health monitoring (scrapers break) + data-quality validation is the operational core interviewers probe (the freshness-vs-crawl-cost trade-off and scraper fragility are key)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "PRODUCT MATCHING ACCURACY (entity resolution) is THE hard problem — wrong matches conflate different products, missed matches fragment one -> UPC/GTIN when available + fuzzy/ML attribute matching; both error types hurt comparison. FRESHNESS vs CRAWL COST — can't re-crawl everything constantly -> prioritize popular/volatile products (limited budget). SOURCE VARIETY/BREAKAGE — scrapers are brittle (site changes), sources block/rate-limit -> per-source connectors + health monitoring + APIs/feeds where possible. SCALE — millions of listings/products -> scalable ingestion + index. DATA QUALITY — bad parses (wrong prices) erode trust -> validation. Trade-offs: APIs/feeds (structured, reliable — not all retailers offer them) vs scraping (universal coverage — brittle, adversarial, maintenance-heavy); UPC/GTIN matching (precise — not always present) vs fuzzy/ML matching (handles missing codes — error-prone); aggressive re-crawl (fresh prices — high crawl cost, source strain) vs lazy (cheap — stale prices mislead); prioritized crawl (fresh where it matters — long-tail staler) vs uniform (fair — wasteful); cache serving (fast read-heavy — slight price staleness) vs always-fresh. Closing signal: ingest from many sources (APIs + brittle web scraping with health monitoring), NORMALIZE and MATCH listings into canonical products via entity resolution (UPC/GTIN when available, else fuzzy/ML attribute matching — the crux), store/index for read-heavy cached compare/search, and keep prices fresh with prioritized re-crawling (limited budget on popular/volatile products) — a multi-source aggregator whose hard core is product matching, balancing freshness against crawl cost."),
      C("deep_dive", "Deep dive: scraping infra, catalog, monetization & operations",
        "Operationally a price aggregator is a data-ingestion + entity-resolution + search product. Ingestion infrastructure: a crawler/scraper fleet (per-source parsers), a feed/API connector framework, scheduling + rate limiting (respect robots.txt, avoid bans), proxy/rotation for scraping at scale, and BREAKAGE detection (a parser yielding no/garbage data -> alert) — scraper maintenance is a major ongoing cost (sites change constantly). Catalog / canonical products: the entity-resolution output is a product CATALOG (canonical products with normalized attributes), continuously updated as new listings arrive and matched; manage merges/splits (fix bad matches), and use product identifiers (GTIN), title/attribute matching, and ML/embeddings for hard cases; human review for ambiguous matches. Price store & history: prices per product per retailer, with HISTORY (price-history charts, deal detection) and alerts (notify when a price drops). Search & comparison: a search index over the catalog (the search-engine pattern) for product search; comparison pages rank retailers (by price + availability + trust/affiliate); category browsing + filters. Data quality: validate prices (sanity bounds), reconcile conflicting source data, handle availability/stock, and currency. Freshness: prioritize re-crawl by popularity + volatility (limited budget), and prefer push feeds where available. Monetization: affiliate links + click tracking (revenue when users click through to retailers) — and ranking must balance user value vs affiliate incentives (trust). Scale: ingestion, catalog/matching, and serving scale independently; sharded by product/category. Adversarial sources: some retailers don't want to be scraped (legal/ToS + technical blocking) — navigate this (use feeds, partnerships). Observability: ingestion success/breakage per source, match accuracy (mis-matched/fragmented products), price freshness/staleness, and search/compare latency are the SLOs. The spine holds: multi-source ingestion (APIs + maintained scrapers) + entity-resolution catalog + price store/history + read-heavy cached search/compare + prioritized freshness, with data-quality + affiliate monetization."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'What's the hard part?' PRODUCT MATCHING / entity resolution — the same product is listed differently by each retailer (different titles/SKUs), so you must recognize they're the SAME product to compare prices; without it, comparison is impossible. 'How do you match?' use strong identifiers (UPC/GTIN/MPN) when present (exact); otherwise fuzzy-match on normalized title + brand/model + attributes, increasingly with ML/embeddings — accepting some error (false matches conflate, misses fragment). 'How do you ingest from many retailers?' APIs/feeds where available + WEB SCRAPING otherwise (per-source parsers) — scraping is brittle (sites change -> breakage) and adversarial (blocking/rate limits), needing maintenance + health monitoring. 'Keep prices fresh?' re-crawl regularly but PRIORITIZE popular/volatile products (limited crawl budget) — stale prices mislead users; use push feeds where possible. 'Serve comparison?' a search index + per-retailer price store, read-heavy + cached; price history + deal alerts. 'Scrapers break?' monitor ingestion per source, detect no/garbage data, alert + fix parsers (ongoing). 'Data quality?' validate prices (sanity bounds), reconcile conflicts. 'Monetization?' affiliate links + click tracking (balance with ranking trust). Each returns to the spine: multi-source ingestion + product matching (entity resolution, the crux) + store/index + prioritized-freshness re-crawl + read-heavy compare/search."),
    ],
    "A price-comparison aggregator tests multi-source INGESTION (retailer APIs + brittle web SCRAPING with breakage monitoring) and — the hard core — PRODUCT MATCHING / entity resolution (recognizing the same product listed differently across retailers via UPC/GTIN when available, else fuzzy/ML attribute matching) into a canonical catalog, served read-heavy + cached for compare/search, with FRESHNESS via prioritized re-crawling (limited budget on popular/volatile products). The signal is ingestion + entity-resolution product matching + freshness, not just 'store and display prices'.",
    [
      G("ignore_matching", "Assuming products are easily identifiable across retailers.", "Product matching / entity resolution is the hard part — the same product is listed differently per retailer; match via UPC/GTIN or fuzzy/ML attribute matching.", "Joins listings by exact title/SKU; fails to group the same product across retailers, so comparison breaks."),
      G("scrape_naively", "Treating ingestion as a simple, stable scrape.", "Scraping is brittle + adversarial (sites change/block) — use APIs/feeds where possible, per-source maintained parsers, and breakage monitoring.", "One generic scraper with no health monitoring; breaks silently when sites change."),
      G("ignore_freshness", "Crawling everything uniformly / showing stale prices.", "Prioritize re-crawl by popularity + volatility (limited budget); stale prices mislead users — refresh where it matters.", "Re-crawls all products on a fixed schedule (wasteful) or rarely (stale prices)."),
    ],
    0.5, DIAG.priceagg, "Price-comparison aggregator architecture"),

  // ───────────────────── ONLINE LEARNING PLATFORM ──────────────────────────
  TT("sysd_m20", "sysd_m20_t1", 1, "Design an Online Learning Platform", "design-online-learning",
    ["case-study", "video", "progress", "education"],
    "Instructors upload courses of video lessons and quizzes; millions of students enroll, stream the videos on any device, take assessments, and pick up exactly where they left off. The bulk of the load and cost is video. How do you build an online learning platform (Coursera/Udemy)?",
    "Courses are structured content (video lessons + quizzes + materials); VIDEO is the heavy part — uploaded videos are transcoded into adaptive bitrates (media pipeline) and delivered via CDN (video streaming), the dominant load/cost. Students ENROLL, watch, and take ASSESSMENTS, with per-student PROGRESS/completion tracked; instructors manage content. It composes the media-pipeline + video-streaming + progress-state patterns. Video delivery at scale + progress/enrollment/assessments are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: instructors CREATE COURSES (structured: video LESSONS + QUIZZES + materials); students ENROLL, WATCH videos, take ASSESSMENTS/quizzes, and track PROGRESS (resume where they left off, completion, certificates); search/recommend courses. Non-functional: VIDEO DELIVERY at scale (the dominant load — many students streaming on varied devices/networks), PROGRESS tracking per student, SCALE (many learners + courses), content management, and reasonable cost (video is expensive). Clarify scope: an online learning / MOOC platform (Coursera / Udemy / Khan Academy style). It COMPOSES earlier designs: the bulk of the system is VIDEO — uploaded course videos must be processed (transcoded into multiple qualities — the MEDIA-PROCESSING pipeline) and DELIVERED to many students at scale (the VIDEO-STREAMING + CDN design) — this is the dominant load and cost, and the defining technical challenge (delivering video smoothly to many learners on different devices/bandwidths). Beyond video: COURSE STRUCTURE/content management (lessons, modules, materials), ENROLLMENT, per-student PROGRESS TRACKING (which lessons completed, resume position, quiz scores, completion/certificates), and ASSESSMENTS (quizzes, grading — sometimes auto-graded, sometimes peer/assignment). So the design centers on video delivery at scale (media pipeline + streaming) + the learning layer (enrollment, progress tracking, assessments, content)."),
      K("estimation", "Capacity estimation (with numbers)",
        "Video: the dominant load -> uploaded videos transcoded (ABR renditions) + delivered via CDN.\n  many students streaming concurrently on varied devices/bandwidth -> CDN absorbs it.\nCourses: structured content (lessons/modules + quizzes + materials) -> content store.\nProgress: per student per course -> lessons completed, resume position, quiz scores.\nEnrollment: student -> courses enrolled.\nTakeaway: video delivery (media pipeline -> CDN) is the heavy part; plus enrollment +\nper-student progress tracking + assessments + content management."),
      C("hld", "High-level design",
        "CONTENT: a course is structured content — MODULES/lessons containing VIDEOS, QUIZZES, and materials (PDFs, etc.) — managed via an instructor authoring experience and stored in a content/metadata store. VIDEO (the heavy part): when an instructor uploads a lesson video, it goes through a MEDIA-PROCESSING pipeline — transcoded into multiple resolutions/bitrates and packaged for ADAPTIVE BITRATE streaming (the media-pipeline design) — and stored, then DELIVERED to students via a CDN (the video-streaming design) so it plays smoothly on any device/network at scale (the dominant load). ENROLLMENT: students enroll in courses (free/paid — payments for paid courses). LEARNING + PROGRESS: as a student watches lessons and completes quizzes, the platform TRACKS per-student PROGRESS — which lessons are completed, the resume position in a video, quiz scores, and overall course completion (-> certificates) — stored per student per course so they can resume exactly where they left off across devices. ASSESSMENTS: quizzes (auto-graded), assignments (graded/peer-reviewed), and exams. Around this: course SEARCH/discovery + recommendations, reviews/ratings, and instructor analytics. Trace it: instructor uploads a course -> videos transcoded (media pipeline) -> stored + CDN-ready; student enrolls -> watches a lesson (streamed via CDN, ABR) -> progress updated (lesson complete, resume position) -> takes a quiz (graded) -> completes course -> certificate. Course content + video (media pipeline -> CDN) + enrollment + per-student progress tracking + assessments is the shape."),
      K("api", "API / flow",
        "author: instructor creates course (modules/lessons + quizzes + materials)\nupload video -> media pipeline (transcode to ABR renditions) -> store -> CDN-ready\nenroll: student -> course (free/paid: payment)\nwatch: stream video via CDN (adaptive bitrate) ; track resume position\nprogress: per student per course -> lessons completed, quiz scores, completion -> certificate\nassess: quizzes (auto-grade), assignments (grade/peer-review)\ndiscover: course search + recommendations + reviews"),
      K("data_model", "Data model",
        "courses: structure (modules/lessons), videos, quizzes, materials, instructor\nvideos: transcoded ABR renditions in object storage -> CDN delivery\nenrollments: student -> courses\nprogress: (student, course) -> lessons completed, resume position, quiz scores, completion\nassessments: quizzes/assignments + grading\ncatalog: search index + recommendations + reviews"),
      C("deep_dive", "Deep dive: video delivery at scale",
        "The dominant technical challenge — and most of the load/cost — is VIDEO. PROCESSING (media pipeline): instructors upload course videos, which must be TRANSCODED into multiple resolutions/bitrates and packaged for ADAPTIVE BITRATE streaming (HLS/DASH) so they play well on any device and bandwidth (the MEDIA-PROCESSING-PIPELINE design: upload -> object storage -> async transcode into renditions -> store outputs); this is done ASYNCHRONOUSLY (transcoding is slow) when a course is published, and is a real cost (CPU-heavy). DELIVERY (video streaming + CDN): the processed videos are DELIVERED to students via a CDN (the VIDEO-STREAMING design) — students stream from a nearby edge with adaptive bitrate (the player switches quality based on their connection), so playback is smooth at scale; the CDN absorbs the massive streaming traffic (many concurrent learners) and provides global low-latency, while origin (object storage) serves cache-misses. This video pipeline + CDN delivery is WHY online learning is fundamentally a video-delivery system at its core — it's the heaviest, most expensive, most scalability-critical part, and reuses the media-processing + streaming patterns wholesale. RESUME / playback features: track each student's RESUME POSITION in a video (so they continue where they stopped, across devices), playback speed, captions/subtitles (transcribed, multi-language), and quality selection. COST management: video transcoding + CDN egress are the big costs — optimize (only-needed renditions, efficient codecs, CDN caching). For LIVE classes (some platforms), live streaming (the live-streaming design) instead of/in addition to VOD. So media-pipeline transcoding (ABR) + CDN delivery (the dominant load/cost) + resume/playback features is the video core interviewers probe — recognizing online learning is largely a video system."),
      C("deep_dive", "Deep dive: enrollment, progress tracking & assessments",
        "The learning layer on top of video is enrollment, per-student PROGRESS, and assessments. ENROLLMENT: students enroll in courses (free or PAID — paid courses integrate payments/subscriptions — the payment/billing patterns); enrollment grants access to the course content and is the basis for the student's relationship to a course. PROGRESS TRACKING (a defining feature): the platform tracks, PER STUDENT PER COURSE, their PROGRESS — which lessons/modules are COMPLETED, the RESUME position within a video, quiz SCORES, time spent, and overall COURSE COMPLETION (driving certificates) — so students can resume EXACTLY where they left off (across devices), see their progress, and the platform can track completion/engagement. This is per-user state at scale (many students × many lessons) — a write on each lesson view/completion/quiz — stored in a progress store keyed by (student, course), and synced across the student's devices (continue on phone where you left off on laptop). ASSESSMENTS: courses include QUIZZES (typically AUTO-GRADED — multiple choice, etc. — instant feedback), ASSIGNMENTS (graded — sometimes by instructors, sometimes PEER-reviewed at MOOC scale, since instructors can't grade thousands), and EXAMS (proctored for credentials) — assessment results feed progress + certificates; auto-grading is preferred for scale. CERTIFICATES/credentials: on completion, issue a certificate (verifiable). CONTENT MANAGEMENT: instructors author + update courses (structure, videos, quizzes), versioning. DISCOVERY: course search + recommendations (the search + recsys patterns) help students find courses. ENGAGEMENT: progress, streaks, discussion forums (the community pattern), and reminders drive completion (online-course completion rates are notoriously low). So enrollment + per-student progress tracking (resume/completion, synced) + assessments (auto-graded quizzes + peer-reviewed assignments at scale) + certificates is the learning-layer core interviewers probe (atop the video system)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "VIDEO DELIVERY / COST is the dominant concern — transcoding (CPU) + CDN egress -> media pipeline (only-needed renditions, efficient codecs) + CDN caching; the heaviest part. PROGRESS at scale — per-student-per-lesson writes for millions of learners -> a scalable progress store, batched/efficient writes, synced across devices. ASSESSMENT at scale — can't human-grade thousands -> auto-graded quizzes + peer review for assignments. CONTENT MANAGEMENT — instructors author/update; versioning. ENGAGEMENT/completion — low completion rates -> progress/reminders/community. Trade-offs: rich video (multiple renditions, captions, smooth ABR — transcoding + CDN cost) vs minimal (cheap — poor experience); track granular progress (resume, analytics, sync — write volume) vs coarse (cheap — worse UX); auto-graded quizzes (scalable, instant — limited to objective questions) vs human/peer grading (handles open-ended — slow/inconsistent, peer review at MOOC scale); VOD (scalable, cacheable — not live) vs live classes (real-time engagement — live-streaming complexity); paid courses (revenue — payment integration) vs free. Closing signal: structure courses as content (video lessons + quizzes + materials); process videos via a media pipeline (transcode to ABR) and deliver via CDN (the dominant load/cost — it's largely a video system); handle enrollment, track per-student progress (resume/completion, synced across devices), and assess via auto-graded quizzes + peer-reviewed assignments at scale, with certificates — composing the media-pipeline, video-streaming, progress-state, and search/recsys patterns into a scalable learning platform."),
      C("deep_dive", "Deep dive: live classes, engagement, analytics & operations",
        "Operationally an online learning platform spans content, video, and learner engagement. VOD vs live: most content is VOD (transcoded + CDN — scalable), but some platforms offer LIVE classes/cohorts (live streaming + real-time interaction — the live-streaming design) and webinars; live adds real-time complexity. Content authoring & management: an instructor studio to create/structure courses (modules, video upload, quizzes, materials), versioning, drafts/publishing, and bulk operations; content moderation/quality review for marketplaces (Udemy). Captions/accessibility: auto-transcription (speech-to-text) + multi-language subtitles + accessibility (important + sometimes legally required). Progress + sync: per-student progress (completion, resume position, scores) stored + synced across devices (the offline-sync-ish pattern for resume); offline download for mobile (DRM-protected). Assessments: auto-graded quizzes (objective), code-graded assignments (a code-judge for programming courses — sandboxed execution), peer-graded assignments (at MOOC scale, with rubrics + calibration), and proctored exams (identity + monitoring) for credentials. Certificates/credentials: issue verifiable certificates on completion (sometimes blockchain-backed/verifiable). Engagement & analytics: discussion forums (community design), Q&A, notes, reminders, streaks, and learner analytics (where students drop off — instructor analytics) to improve completion (notoriously low). Discovery: course catalog search (search-engine pattern) + recommendations (recsys) + reviews/ratings. Payments: paid courses/subscriptions (payment + subscription-billing designs), instructor payouts (marketplace), refunds. Scale: video (media pipeline + CDN) dominates; content, progress, assessments, and catalog scale independently. DRM: protect paid video content (encrypted streaming + DRM). Observability: video QoE (startup time, rebuffering, bitrate), CDN hit rate/cost, progress-write throughput, assessment grading, and completion/engagement metrics are the SLOs. The spine holds: course content + media-pipeline-transcoded CDN-delivered video (VOD + optional live) + enrollment/payments + per-student progress (synced) + scalable assessments + certificates + discovery/engagement."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'What's the dominant part?' VIDEO — uploaded lessons are transcoded into adaptive bitrates (media pipeline) and delivered via CDN (video streaming); this is the heaviest load + cost, so online learning is largely a video-delivery system. 'Smooth playback on any device?' adaptive bitrate streaming (HLS/DASH) from a CDN (the player adapts quality to bandwidth). 'Resume where I left off?' track per-student resume position + completion, synced across devices. 'Progress at scale?' a per-(student,course) progress store (lessons completed, scores, completion) — write on each view/completion; scalable + synced. 'Assessments at MOOC scale?' auto-graded quizzes (objective), code-graded for programming (a sandboxed judge), and PEER-reviewed assignments (instructors can't grade thousands); certificates on completion. 'Paid courses?' enrollment + payments/subscriptions + instructor payouts (marketplace). 'Live classes?' live streaming + real-time interaction (vs scalable VOD). 'Low completion rates?' engagement — progress, reminders, forums, analytics on drop-off. 'Discovery?' course search + recommendations + reviews. 'Cost?' video (transcoding + CDN egress) — optimize renditions/codecs/caching; DRM for paid content. Each returns to the spine: media-pipeline + CDN video (the heavy part) + enrollment + per-student progress (synced) + scalable assessments + certificates + discovery/engagement."),
    ],
    "An online learning platform tests recognizing it's largely a VIDEO system: process course videos via a media pipeline (transcode to adaptive bitrates) and deliver via CDN (the dominant load/cost — composing the media-pipeline + video-streaming patterns), PLUS the learning layer — enrollment, per-student PROGRESS tracking (resume position/completion, synced across devices), and scalable ASSESSMENTS (auto-graded quizzes + peer-reviewed assignments at MOOC scale) with certificates, over structured course content. The signal is video-delivery-at-scale + progress/enrollment/assessments, not just a content CRUD app.",
    [
      G("ignore_video_scale", "Treating video as simple file serving, ignoring transcoding + CDN.", "Process videos via a media pipeline (transcode to adaptive bitrates) + deliver via CDN — video is the dominant load/cost, the core of the system.", "Serves raw uploaded videos from a server/DB; no transcoding/ABR/CDN; poor playback + huge cost."),
      G("no_progress_tracking", "Not tracking per-student progress / resume state.", "Track per-(student,course) progress (completion, resume position, scores), synced across devices — a defining learning feature.", "No progress/resume; students can't continue where they left off or see completion."),
      G("unscalable_grading", "Assuming all assessments can be human-graded.", "Use auto-graded quizzes (+ code-judge for programming) and peer review for open-ended assignments at MOOC scale — instructors can't grade thousands.", "Plans manual grading of every assignment; doesn't scale to many students."),
    ],
    0.4, DIAG.onlinelearning, "Online learning platform architecture"),

  // ───────────────────────── LOYALTY / REWARDS ─────────────────────────────
  TT("sysd_m20", "sysd_m20_t6", 6, "Design a Loyalty / Rewards System", "design-loyalty-rewards",
    ["case-study", "ledger", "accuracy", "rules-engine"],
    "Customers earn points on purchases, climb tiers, and redeem points for rewards — and because points have real monetary value, you can never award them twice, let someone spend points they don't have, or lose a balance. How do you build a loyalty/rewards system that's accurate like accounting?",
    "Maintain a points LEDGER per member — an append-only record of EARN and REDEEM transactions (like accounting, for accuracy + audit) whose sum is the balance; a RULES ENGINE computes earnings (points per $, promotions, tiers); REDEMPTION atomically deducts points (no double-spend / overspend); and idempotency prevents double-awarding. Because points have value, ACCURACY/integrity is central. Points ledger/accuracy + rules engine/redemption/tiers are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: AWARD points for actions/PURCHASES (earn rules — e.g. points per dollar, bonuses), track each member's BALANCE, let members REDEEM points for rewards, support TIERS (status levels from activity), promotions, and point EXPIRY. Non-functional: ACCURACY / INTEGRITY (points have real monetary VALUE, so balances must be EXACTLY correct — never double-award, never let someone spend points they don't have or overspend, never lose points), AUDITABILITY (traceable point history), reliability, and scale. Clarify scope: a loyalty/rewards points system. The defining requirement is ACCURACY/INTEGRITY because POINTS ARE LIKE MONEY: a member's balance has real value (redeemable for rewards/discounts), so the system must be transaction-accurate — every EARN and REDEEM must be recorded correctly, you must NEVER double-award (a retry awarding points twice = giving away value), NEVER allow OVERSPENDING or double-spend (redeeming more than the balance, or the same points twice), and never lose points — exactly the correctness bar of a financial system. This points strongly to an ACCOUNTING-style design: an append-only LEDGER of point transactions (earn/redeem) whose balance is derived/maintained accurately, with idempotency and atomic redemption. Layered on: a RULES ENGINE for earn rules/promotions/tiers, redemption, and expiry. So the design centers on the points ledger (accuracy/integrity) + the rules engine/redemption/tiers."),
      K("estimation", "Capacity estimation (with numbers)",
        "Members: many ; transactions: earn (per purchase/action) + redeem -> per-member ledger.\nAccuracy: points = value -> NEVER double-award / overspend / lose points (financial-grade).\nLedger: append-only earn/redeem entries -> balance = sum (or maintained balance) ; audit.\nRedemption: atomic deduct -> no double-spend, no overspend (check balance + deduct atomically).\nIdempotency: a purchase/award processed once (retries don't double-award).\nTakeaway: an accounting-style append-only points ledger (accuracy + audit) + a rules engine\n(earn/tiers/promotions) + atomic redemption (no double-spend) + idempotency."),
      C("hld", "High-level design",
        "Each member has a points LEDGER — an APPEND-ONLY record of point TRANSACTIONS (EARN entries from purchases/actions, REDEEM entries from spending points, plus adjustments/expirations) — like an accounting ledger; the member's BALANCE is the sum of the ledger (or a maintained running balance reconciled against it). EARNING: when a qualifying action/PURCHASE happens, a RULES ENGINE computes the points to award (earn rules — e.g. 1 point per $1, category bonuses, promotions, tier multipliers) and APPENDS an earn entry — IDEMPOTENTLY (keyed by the transaction so a retry doesn't double-award). REDEMPTION: when a member redeems points for a reward, the system ATOMICALLY checks the balance is sufficient and DEDUCTS the points (append a redeem entry) in one atomic operation — preventing OVERSPENDING (can't redeem more than you have) and DOUBLE-SPEND (the same points twice / concurrent redemptions) — exactly like an atomic debit. TIERS: a member's tier/status is computed from their activity (e.g. points/spend in a period) and grants benefits/multipliers. EXPIRY: points may expire after a period (a scheduled process expires old points — append expiry entries). Everything is AUDITABLE (the ledger IS the audit trail). Trace it: member buys -> rules engine computes points -> append earn entry (idempotent) -> balance up; member redeems a reward -> atomic balance-check + deduct (append redeem) -> no overspend; tier recomputed; old points expire. Append-only points ledger (accuracy/audit) + rules engine (earn/tiers) + atomic redemption (no double-spend) + idempotency is the shape."),
      K("api", "API / flow",
        "earn: action/purchase -> rules engine computes points -> append EARN entry (idempotent by txn)\nbalance: sum of ledger (or maintained running balance, reconciled)\nredeem: atomic { check balance >= cost ; append REDEEM entry } -> no overspend / double-spend\ntiers: compute member tier/status from activity -> benefits/multipliers\nexpiry: scheduled job expires old points (append expiry entries)\naudit: the ledger is the immutable history (every earn/redeem/adjust)"),
      K("data_model", "Data model",
        "members: id + tier/status + (maintained) balance\nledger: append-only entries (member, type: earn|redeem|adjust|expire, points, ref txn, ts)\n  -> balance = sum ; immutable audit trail\nidempotency: per source transaction -> no double-award\nrules: earn rules / promotions / tier thresholds + multipliers\nredemptions: reward catalog + redeem entries (atomic deduct)"),
      C("deep_dive", "Deep dive: the points ledger & accuracy (points are money-like)",
        "The foundation is treating points like MONEY and using an ACCOUNTING-style ledger for correctness. WHY: points have real VALUE (redeemable), so the system needs financial-grade accuracy — a wrong balance means giving away value (over-credit) or cheating the customer (under-credit/lost points), and errors are costly + erode trust. THE LEDGER: instead of just storing a mutable balance number (error-prone — a lost update or double-apply silently corrupts it), use an APPEND-ONLY LEDGER of point TRANSACTIONS (each earn, redeem, adjustment, expiration is an immutable entry), and the BALANCE is the SUM of the ledger (or a maintained running balance that's reconcilable against the ledger) — the same double-entry/transaction-log approach as accounting/banking. This gives ACCURACY (the balance is derived from a complete, auditable history) and AUDITABILITY (you can explain every point — when earned/spent, from which transaction — for disputes + reconciliation). IDEMPOTENCY (no double-award): earning is triggered by external events (a purchase) that can be RETRIED or arrive more than once, so each award must be IDEMPOTENT — keyed by the source transaction id, so reprocessing the same purchase does NOT award points twice (a classic correctness bug — retries giving away value); the ledger records each award once. ATOMIC, CONSISTENT updates: appending entries + updating the balance must be consistent (a transaction), so concurrent operations don't corrupt the balance (no lost updates). RECONCILIATION: periodically reconcile maintained balances against the ledger sum to catch drift. So an append-only transaction LEDGER (balance = sum, auditable) + IDEMPOTENT earning (no double-award) + consistent/atomic updates — treating points with financial-grade accuracy — is the core interviewers probe (the wrong instinct is a single mutable balance counter, which is unsafe for value-bearing points)."),
      C("deep_dive", "Deep dive: rules engine, atomic redemption, tiers & expiry",
        "Around the ledger sit the loyalty mechanics: earning rules, safe redemption, tiers, and expiry. RULES ENGINE (earning): points aren't a flat 'per purchase' — there are EARN RULES (e.g. 1 point per $1, 2x on category X, bonus for actions), PROMOTIONS (limited-time multipliers/bonuses), and TIER multipliers (gold members earn 1.5x) — so a configurable RULES ENGINE computes how many points an action earns based on the action + member tier + active promotions; this needs to be flexible (marketers change rules/promotions often) and correct. ATOMIC REDEMPTION (no double-spend/overspend — the redemption-side correctness): when a member redeems points for a reward, you must ATOMICALLY (1) verify the balance is SUFFICIENT and (2) DEDUCT the points (append a redeem entry / decrement balance) as ONE atomic operation — exactly like the flash-sale atomic-decrement / a bank debit — so that two concurrent redemptions can't both succeed against the same balance (double-spend) and you can never redeem MORE than you have (overspend); idempotency on the redemption (a retry doesn't deduct twice). This atomic check-and-deduct is the redemption correctness crux. TIERS: a member's TIER/status (Silver/Gold/Platinum) is computed from their activity (points earned or spend over a period) and grants benefits (earn multipliers, perks) — recomputed as activity changes (and tiers may downgrade if activity drops); tier computation must be consistent. EXPIRY: points often EXPIRE after a period of inactivity or a fixed term — a scheduled process identifies and EXPIRES old points (appending expiry entries, FIFO — oldest points first), which is a common source of disputes so it must be accurate + transparent. REDEMPTION CATALOG: the rewards/items points can be redeemed for (with point costs). So a flexible rules engine (earn/promotions/tiers) + atomic redemption (no double-spend/overspend) + tier computation + accurate expiry is the mechanics core interviewers probe (atomic redemption is the must-get-right alongside no-double-award)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "ACCURACY/INTEGRITY (points = money) is paramount — append-only ledger + idempotent earning + atomic redemption + reconciliation; errors give away value or cheat members. DOUBLE-AWARD — retried/duplicate earn events -> idempotency by source transaction. DOUBLE-SPEND / OVERSPEND — concurrent or retried redemptions -> atomic check-and-deduct (+ idempotency). RULES COMPLEXITY — frequently-changing earn rules/promotions/tiers -> a flexible rules engine. SCALE — many members/transactions -> partition by member; the ledger grows (archive). EXPIRY accuracy — disputes -> precise FIFO expiry + transparency. Trade-offs: append-only ledger (accurate, auditable, reconstructable — storage + sum/maintained-balance) vs single mutable balance (simple — unsafe for value: lost updates/double-apply corrupt it); idempotent earning (no double-award — track source txn ids) vs naive (double-awards on retry — gives away value); atomic redemption (no overspend/double-spend — serialize per member) vs read-then-deduct (races -> overspend); maintained balance + reconcile (fast reads, audited — reconciliation) vs always-sum-ledger (always correct — slower); flexible rules engine (marketer-configurable — complexity) vs hardcoded (simple — inflexible). Closing signal: an append-only points LEDGER (balance = sum, auditable) for financial-grade accuracy, IDEMPOTENT earning via a flexible rules engine (no double-award), ATOMIC redemption (no overspend/double-spend), tier computation from activity, and accurate FIFO expiry — treating points like money, so balances are always correct, every point is traceable, and value is never double-awarded or double-spent."),
      C("deep_dive", "Deep dive: integrations, fraud, scale & operations",
        "Operationally a loyalty system is value-bearing financial infrastructure integrated across channels. Earning integrations: points are earned from many sources (purchases via POS/e-commerce, app actions, partner activity), so the system ingests EARN events from these channels (idempotently) + applies rules — reliable event ingestion (the webhook/queue patterns) so no earning event is lost or double-counted. Rules/promotions management: a configurable rules engine + admin tools for marketers to define earn rules, promotions, bonus campaigns, and tier structures without code; A/B test offers. Redemption catalog & fulfillment: rewards (discounts, products, gift cards, experiences) with point costs; redemption atomically deducts + triggers fulfillment (a workflow), with handling for failed fulfillment (refund points). Fraud & abuse: points have value, so they're a fraud target (fake accounts farming points, exploiting promotions, account takeover to steal points) — fraud detection + limits + monitoring (the fraud-detection design). Reconciliation & accounting: reconcile point balances/liability for FINANCIAL reporting (outstanding points are a liability on the books) — accuracy matters for accounting, not just UX; audit trail (the ledger) supports it. Expiry & breakage: scheduled FIFO expiry; 'breakage' (unredeemed expiring points) is financially modeled. Scale & partitioning: shard by member; the ledger grows -> archive old entries (keep balance + recent history); high transaction volume on busy periods. Tier lifecycle: periodic tier recomputation (upgrade/downgrade), member notifications. Multi-program / partners: coalition loyalty (points across partner brands) adds cross-system reconciliation. Member-facing: balance, history, tier status, redemption — real-time + consistent. Observability: balance accuracy (reconciliation drift = 0), double-award/double-spend incidents (must be 0), earn/redeem throughput, expiry accuracy, and fraud rates are the SLOs. The spine holds: append-only ledger (accuracy/audit) + idempotent rules-engine earning + atomic redemption + tiers/expiry, integrated across channels, fraud-protected and reconciled for accounting."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'Why an accounting-style ledger, not a balance counter?' points have VALUE (money-like), so you need financial-grade accuracy + auditability — an append-only ledger of earn/redeem transactions (balance = sum) lets you reconstruct + audit every point and resists the lost-update/double-apply corruption a single mutable counter suffers. 'Don't double-award points?' make earning IDEMPOTENT — keyed by the source transaction id, so a retried/duplicate purchase event doesn't award twice (that gives away value). 'Don't let someone overspend / double-spend?' ATOMIC redemption — check balance + deduct in one atomic operation (like a bank debit / flash-sale decrement), so concurrent or retried redemptions can't overspend or double-spend; idempotent redemption. 'Earn rules?' a flexible rules engine (points per $, category bonuses, promotions, tier multipliers) marketers can configure. 'Tiers?' computed from activity (spend/points over a period), granting multipliers/perks; recomputed (upgrade/downgrade). 'Expiry?' scheduled FIFO expiry of old points (accurate + transparent — a dispute source). 'Fraud?' points are a target (farming, account takeover) -> fraud detection + limits. 'Accounting?' outstanding points are a liability -> reconcile balances for financial reporting. 'Scale?' shard by member; archive old ledger entries. Each returns to the spine: append-only points ledger (accuracy/audit) + idempotent rules-engine earning + atomic redemption (no double-spend) + tiers/expiry."),
    ],
    "A loyalty/rewards system tests treating points like MONEY: an append-only points LEDGER (earn/redeem transactions, balance = sum, auditable) for financial-grade accuracy, IDEMPOTENT earning via a flexible rules engine (no double-award on retries), ATOMIC redemption (no overspend/double-spend), tier computation from activity, and accurate FIFO expiry — fraud-protected and reconciled as an accounting liability. The signal is an accounting-style ledger + idempotent earning + atomic redemption (accuracy/integrity), not a single mutable balance counter.",
    [
      G("mutable_balance", "Storing only a mutable balance number (no ledger).", "Use an append-only transaction ledger (balance = sum, auditable) — points are value, so a mutable counter risks lost-update/double-apply corruption and isn't auditable.", "Increments/decrements a single balance field; no transaction history; corruption/audit gaps."),
      G("double_award", "Awarding points without idempotency on earn events.", "Make earning idempotent (keyed by source transaction) so retried/duplicate purchase events don't award points twice (giving away value).", "Adds points each time an earn event is received; retries double-award."),
      G("overspend_redeem", "Read-then-deduct redemption (non-atomic).", "Atomically check balance + deduct (like a bank debit) so concurrent/retried redemptions can't overspend or double-spend; idempotent redemption.", "Reads balance, then deducts separately; concurrent redemptions overspend / double-spend."),
    ],
    0.5, DIAG.loyalty, "Loyalty / rewards architecture"),

  // ─────────────────── SPORTSBOOK / LIVE BETTING ───────────────────────────
  TT("sysd_m20", "sysd_m20_t8", 8, "Design a Sportsbook / Live Betting Platform", "design-sportsbook",
    ["case-study", "betting", "real-time", "risk"],
    "A bettor places a wager on a soccer match at the odds shown — but during a live game the odds shift second-by-second as goals are scored, and you must accept bets at the right odds, never let someone exploit a stale price, manage your own exposure so a single outcome doesn't bankrupt you, and pay out correctly when the match ends. How do you build a sportsbook?",
    "An ODDS engine sets and continuously UPDATES odds (especially live/in-play, fast as the game changes); bets are accepted with the odds LOCKED at placement time (validate/re-confirm to prevent stale-odds exploits); RISK MANAGEMENT tracks exposure/liability and adjusts odds to balance the book; and bets are SETTLED accurately when outcomes are known (payouts) — all money-critical and real-time. Real-time odds + bet placement integrity + risk management + settlement are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: offer betting MARKETS with ODDS on events (sports, esp. LIVE/in-play), accept BETS from users, UPDATE odds in real-time as conditions change, manage the book's RISK, and SETTLE bets (pay out) when outcomes are determined. Non-functional: REAL-TIME odds UPDATES (live/in-play odds change fast as the game unfolds), bet acceptance INTEGRITY (accept bets at correct odds — no exploiting stale prices; it's money), RISK MANAGEMENT (don't get bankrupted by lopsided exposure), SETTLEMENT ACCURACY (correct payouts — money), and scale (many users/markets, spikes during big events). Clarify scope: a sportsbook / live-betting platform. The defining challenges, all MONEY-critical: (1) REAL-TIME ODDS — especially for LIVE/in-play betting, odds change CONTINUOUSLY and FAST as the game unfolds (a goal swings the odds instantly), so you must compute + push updated odds in real-time; (2) BET PLACEMENT INTEGRITY under changing odds — because odds change, there's a RACE at placement: a user sees odds, places a bet, but the odds may have moved — you must accept the bet at well-defined odds (LOCK the odds at placement / re-confirm) so a user can't exploit STALE odds (e.g. bet on already-known information / a price you've moved away from); (3) RISK MANAGEMENT — track the book's EXPOSURE/liability across bets and adjust odds to BALANCE the book so one outcome doesn't cause catastrophic loss; and (4) SETTLEMENT — when an outcome is known, settle all bets accurately (pay winners). So the design centers on real-time odds + bet-placement integrity + risk management + accurate settlement."),
      K("estimation", "Capacity estimation (with numbers)",
        "Live odds: update continuously/fast (per game event) -> real-time odds engine + push to users.\nBets: accepted with odds LOCKED at placement (odds change -> race -> re-confirm/lock).\nRisk: track exposure/liability per market -> adjust odds to balance the book (limit max loss).\nSettlement: outcome known -> settle all bets accurately (payouts) -> money integrity.\nSpikes: big events/live moments -> bet + odds-update bursts.\nTakeaway: real-time odds engine + bet placement integrity (lock odds, no stale-odds exploit) +\nrisk management (exposure/balance the book) + accurate settlement (payouts)."),
      C("hld", "High-level design",
        "An ODDS ENGINE computes and continuously UPDATES odds for each market — driven by event data feeds (live scores/stats), models, and risk position — pushing real-time odds to users (especially for LIVE/in-play markets where odds move fast). Users see current odds and PLACE BETS; bet placement carefully handles the odds RACE: the bet is accepted at SPECIFIC, LOCKED odds (the odds at the moment of placement — re-confirmed server-side), and if the odds have MOVED since the user saw them, the system either rejects/re-prompts or applies a policy — preventing a user from exploiting STALE odds (a price you've already moved away from, or betting on near-known outcomes). Accepted bets are recorded (with locked odds, stake, potential payout) — money-critically (no lost/duplicate bets, idempotent). RISK MANAGEMENT continuously tracks the book's EXPOSURE / LIABILITY across all bets per market (how much you'd pay out under each outcome) and ADJUSTS odds (and sets limits) to BALANCE THE BOOK — steering bettors to balance both sides so no single outcome causes catastrophic loss (and to maintain the bookmaker's margin/vig). SETTLEMENT: when an event OUTCOME is determined (final result), all affected bets are SETTLED — winners PAID OUT accurately, losers settled — money-precise + audited. Trace it: live game -> odds engine updates odds (goal -> odds swing) -> pushed to users -> user bets at locked odds (re-confirmed) -> recorded -> risk engine updates exposure + adjusts odds to balance -> game ends -> settle all bets (payouts). Real-time odds engine + bet placement (locked odds, integrity) + risk management (exposure/balance) + accurate settlement is the shape."),
      K("api", "API / flow",
        "odds engine: compute + continuously UPDATE odds (event feeds + models + risk) -> push to users (real-time)\nplace bet: user bets at shown odds -> server LOCKS odds at placement (re-confirm) ->\n  if odds moved -> reject/re-prompt (no stale-odds exploit) ; record bet (idempotent, money)\nrisk mgmt: track exposure/liability per market -> adjust odds + limits to balance the book\nsettle: outcome known -> settle all bets (pay winners accurately) -> audited\nspikes: live moments/big events -> bet + odds-update bursts"),
      K("data_model", "Data model",
        "markets/events: odds per outcome (continuously updated) + status (open/live/settled)\nbets: user, market, outcome, stake, LOCKED odds, potential payout, status\nrisk/exposure: per market liability under each outcome -> balance the book\noutcomes: event results -> trigger settlement\nledger: stakes + payouts (money, accurate, audited)"),
      C("deep_dive", "Deep dive: real-time odds & bet placement integrity",
        "The defining real-time challenge is continuously-changing odds and accepting bets correctly against them. REAL-TIME ODDS: odds are not static — they reflect the current probability + the book's position, and for LIVE/IN-PLAY betting they change CONTINUOUSLY and FAST as the game unfolds (a goal, a red card instantly swings the odds) — so an ODDS ENGINE consumes live event DATA FEEDS (scores/stats), runs pricing models, factors in risk, and pushes UPDATED odds to users in real-time (low latency — like a market data feed; users must see current odds). BET PLACEMENT INTEGRITY (the subtle correctness problem): because odds CHANGE, there's a RACE between a user SEEING odds and their bet being ACCEPTED — by the time the bet arrives, the odds may have MOVED. You must NOT simply accept the bet at whatever the user 'thinks' the odds are, nor at stale odds, because that enables EXPLOITATION: a sharp bettor could bet on a price you've already moved away from, or (worse) on near-certain outcomes during the small latency window (e.g. they saw a goal before your odds updated — 'court-siding'/latency arbitrage). So bet placement LOCKS the odds at the moment of ACCEPTANCE (server-side authoritative odds), and if the odds have CHANGED since the user saw them, the system handles it explicitly: REJECT and re-prompt with new odds, or accept only within a tolerance, or hold briefly — per policy — so the user gets well-defined odds and can't exploit stale prices. Some books add a small acceptance DELAY for live bets to mitigate latency arbitrage. The bet is then recorded with the LOCKED odds, stake, and potential payout — money-critically (idempotent, durable — no lost/duplicate bets). So a real-time odds engine + bet placement that locks server-authoritative odds and handles the odds-change race (preventing stale-odds exploitation) is the integrity core interviewers probe (the wrong instinct is trusting client-shown odds / ignoring the race)."),
      C("deep_dive", "Deep dive: risk management & settlement",
        "The other money-critical pillars are managing the book's RISK and accurately SETTLING bets. RISK MANAGEMENT (don't get bankrupted): a bookmaker takes the other side of every bet, so it has EXPOSURE/LIABILITY — for each market, how much it would have to PAY OUT under each possible outcome; if bets are heavily on one side, a single outcome could cause CATASTROPHIC loss. So the system continuously TRACKS exposure across all bets per market and ADJUSTS to manage it: (1) move the ODDS to make the over-bet side less attractive and the other side more attractive — steering bettors to BALANCE THE BOOK (ideally roughly equal money on each outcome, locking in the bookmaker's margin/vig regardless of result); (2) set bet LIMITS (cap max stake/exposure on a market or from a single bettor); and (3) sometimes lay off risk (hedge with other books). This real-time risk position feeds back into the odds engine (odds reflect both true probability AND the book's position) — risk management is core to a sportsbook's survival, not optional. SETTLEMENT (accurate payouts): when an event's OUTCOME is determined (final score/result — from official feeds), all affected bets must be SETTLED — winners PAID their stake × locked odds, losers' stakes kept, voids/pushes refunded — ACCURATELY (it's money) and reliably (settle every bet exactly once, audited); this is a precise financial operation (a ledger of stakes + payouts), often triggered by the result feed, with handling for disputed/changed results (a result correction must un-settle/re-settle correctly). Settlement at scale (many bets per event) must be fast + correct. INTEGRITY/audit throughout: stakes + payouts are tracked like a financial ledger (accurate, auditable), with idempotency (no double-settle/double-pay). So real-time risk management (track exposure + adjust odds/limits to balance the book) + accurate, idempotent settlement (correct payouts on outcomes) is the money-integrity core interviewers probe (risk management is the part people miss — a sportsbook can be bankrupted by unmanaged exposure)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "REAL-TIME ODDS — live odds change fast -> a low-latency odds engine + push (market-data-like) so users see current prices. BET-PLACEMENT INTEGRITY / odds race — users vs moving odds -> lock server-authoritative odds at placement, handle odds-change (reject/re-prompt), small accept delay vs latency arbitrage. RISK / EXPOSURE — lopsided bets can bankrupt the book -> real-time exposure tracking + adjust odds/limits to balance the book. SETTLEMENT ACCURACY — money -> idempotent, audited settlement; handle result corrections. SPIKES — big events/live moments -> bet + odds-update bursts. Trade-offs: lock odds at placement + reject-on-change (integrity, no stale-odds exploit — occasional re-prompt friction) vs accept-at-shown-odds (smooth UX — exploitable, money loss); accept delay for live bets (mitigates latency arbitrage — slight UX delay) vs instant (responsive — court-siding risk); balance the book via odds (guaranteed margin, low risk — may not always balance) vs take a position (more profit potential — more risk); strict limits (caps exposure — limits big bettors) vs high limits (more volume — more risk); idempotent durable bets/settlement (no double-pay/lost bets — overhead) vs naive (money errors). Closing signal: a real-time ODDS engine (live/in-play, push) + bet placement that LOCKS server-authoritative odds and handles the odds-change race (no stale-odds exploitation) + real-time RISK MANAGEMENT (track exposure, adjust odds/limits to balance the book) + accurate, idempotent SETTLEMENT (correct payouts on outcomes) — a money-critical, real-time system where odds integrity, risk control, and settlement accuracy are paramount."),
      C("deep_dive", "Deep dive: data feeds, fraud, regulation & operations",
        "Operationally a sportsbook is a real-time, money-critical, heavily-regulated platform. Data feeds: odds + settlement depend on real-time, accurate SPORTS DATA feeds (live scores/stats from official providers) and RESULTS feeds — feed latency + accuracy directly affect odds integrity (latency arbitrage) + settlement correctness; redundancy + official sources matter. Odds/pricing: a trading/pricing system (models + traders) sets prices; automated for many markets, with traders managing high-profile/risky ones; the odds engine pushes updates (real-time distribution, like market data — multicast/push). Live-betting specifics: in-play markets update constantly, bets accepted with tight timing controls (accept delay, suspend markets during key moments — e.g. suspend betting when a goal is imminent/scored until odds re-settle) to prevent exploitation. Risk/trading desk: real-time exposure dashboards, automated odds adjustment + limits, hedging/laying off, and liability management per market/event. Settlement: triggered by official results; idempotent, audited payouts; handle voids/pushes, cash-out (let a user settle a bet early at current value — pricing an open bet), and disputed/corrected results (re-settlement). Money handling: deposits/withdrawals, the betting ledger (stakes/payouts/balances — financial-grade accuracy), and payments integration. Fraud & integrity: detect arbitrage abuse, bonus abuse, money laundering (AML/KYC — regulated), match-fixing signals, and bots/court-siding (the fraud-detection design). Regulation/compliance: licensing per jurisdiction, KYC/AML, responsible-gambling (limits, self-exclusion), geo-restrictions, and audit — heavily regulated. Scale: spikes around major events (Super Bowl) -> handle bet + odds-update bursts (queue, scale). Reliability: bets + settlement must never be lost/duplicated (idempotent, durable). Observability: odds-update latency, bet-acceptance latency/rejection rate, exposure/liability per market, settlement accuracy + speed, and fraud/abuse rates are the SLOs. The spine holds: real-time data feeds -> odds engine (push) + bet placement with locked odds/timing controls + real-time risk management (exposure/balance/limits/hedge) + accurate idempotent settlement, money-ledgered, fraud-protected, and regulated (KYC/AML/responsible-gambling)."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you handle live odds?' an odds engine consumes real-time event feeds + models + risk position and continuously pushes updated odds (low-latency, like a market-data feed) — live odds swing fast (a goal moves them instantly). 'Odds change between the user seeing them and betting?' lock SERVER-AUTHORITATIVE odds at placement and handle the race — if odds moved, reject/re-prompt (or accept within tolerance) — so users can't exploit STALE odds; add a small accept delay for live bets to counter latency arbitrage/court-siding. 'Don't get bankrupted?' RISK MANAGEMENT — track exposure/liability per market in real time and adjust ODDS + set LIMITS to balance the book (roughly equal money on each side -> guaranteed margin regardless of outcome), and hedge/lay off. 'Settle bets?' on the official outcome, settle all bets accurately + idempotently (pay winners stake×odds), handle voids/pushes/cash-out + result corrections (re-settle) — money-precise + audited. 'Spikes (big events)?' handle bet + odds-update bursts (scale, queues), suspend markets during key live moments. 'Integrity/fraud?' detect arbitrage/bot/court-siding abuse + AML/KYC (regulated). 'Cash-out?' price an open bet at current value to settle early. 'Money handling?' a financial-grade betting ledger (stakes/payouts/balances). Each returns to the spine: real-time odds engine + bet placement (locked odds, race-handling, timing controls) + risk management (exposure/balance/limits) + accurate idempotent settlement, regulated."),
    ],
    "A sportsbook tests a real-time, money-critical system: a continuously-updating ODDS engine (live/in-play, pushed), bet placement that LOCKS server-authoritative odds and handles the odds-change RACE (no stale-odds exploitation / latency arbitrage), real-time RISK MANAGEMENT (track exposure/liability and adjust odds + limits to balance the book so one outcome can't bankrupt you), and accurate, idempotent SETTLEMENT (correct payouts on outcomes) — over a financial-grade ledger, regulated (KYC/AML). The signal is real-time odds + bet-placement integrity + risk management + settlement accuracy, not a simple bet-and-store app.",
    [
      G("trust_shown_odds", "Accepting bets at the odds the client showed, ignoring the race.", "Lock server-authoritative odds at placement and handle odds-change (reject/re-prompt) — odds move, so accepting stale/client odds is exploitable (money loss).", "Accepts the bet at whatever odds the client sends; bettors exploit stale prices / latency arbitrage."),
      G("no_risk_management", "Taking bets without tracking exposure / balancing the book.", "Track real-time exposure per market and adjust odds + limits to balance the book (and hedge) — lopsided exposure can bankrupt the bookmaker.", "Just records bets; a single outcome creates catastrophic unhedged liability."),
      G("inaccurate_settlement", "Settling/paying out without money-grade accuracy + idempotency.", "Settle accurately + idempotently (no double-pay/lost bets) on official outcomes, audited; handle voids/corrections — it's money.", "Pays out via non-idempotent updates; double-settles on retry or mis-pays; no audit."),
    ],
    0.7, DIAG.sportsbook, "Sportsbook / live betting architecture"),

  // ─────────────────── RESTAURANT RESERVATION (OPENTABLE) ───────────────────
  TT("sysd_m21", "sysd_m21_t1", 1, "Design Restaurant Reservation (OpenTable)", "design-restaurant-reservation",
    ["case-study", "booking", "availability", "consistency"],
    "Diners search for a table for four at 7pm Saturday near them, and book one — and two diners must never end up reserving the same table for the same time. It's the booking problem again, applied to restaurant tables. How do you design a reservation system?",
    "Restaurants have table/slot INVENTORY; users SEARCH availability (by location/date/time/party size) and BOOK a slot via an ATOMIC reservation so two diners can never get the same table at the same time (the booking pattern — atomic reserve, no double-booking, with holds/confirm), backed by an availability calendar, plus reminders/cancellations and overbooking strategy. Atomic no-double-booking + availability search/inventory are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: SEARCH restaurants by location + date/time + PARTY SIZE and see AVAILABILITY; BOOK a table for a specific time/party; manage restaurant table/slot INVENTORY; cancellations, reminders; restaurant-side management. Non-functional: NO DOUBLE-BOOKING (two diners must never reserve the same table for the same time — strong consistency on reservations), accurate real-time AVAILABILITY, good search, and scale. Clarify scope: a restaurant-reservation system (OpenTable / Resy style). This is fundamentally the BOOKING pattern (seen in Airbnb and ticket booking) applied to restaurant TABLES/time-slots — so the core is the SAME as those: (1) preventing DOUBLE-BOOKING — a specific table at a specific time can only be reserved by ONE party, and the naive 'check available then book' RACES, so you need an ATOMIC reservation; and (2) AVAILABILITY SEARCH over INVENTORY — find restaurants with an open table for the requested date/time/party size (over the restaurant's table inventory + existing reservations). The restaurant-specific twists: inventory is TABLES × TIME SLOTS (with table sizes/capacities matched to party size, and turn times — a table is occupied for a dining duration), availability is time-slot-based, and there are domain concerns (no-shows -> sometimes overbooking, waitlists). So the design centers on atomic no-double-booking reservation + availability search over table/slot inventory."),
      K("estimation", "Capacity estimation (with numbers)",
        "Inventory: per restaurant, tables x time-slots (table capacity matched to party size, turn time).\nSearch: by location + date/time + party size -> restaurants with an available matching slot.\nBooking: reserve a specific table/slot ATOMICALLY -> no double-booking (the booking pattern).\nReads >> writes: many searches vs bookings -> read-optimized availability search.\nDomain: no-shows -> overbooking strategy ; waitlists ; reminders/cancellations.\nTakeaway: atomic slot reservation (no double-booking) + availability search over table/slot\ninventory -> the booking pattern applied to restaurant tables."),
      C("hld", "High-level design",
        "Each restaurant has INVENTORY — TABLES (with capacities) across TIME SLOTS (a table is bookable for a dining window/turn time) — represented as an availability calendar (which table-slots are free vs reserved). SEARCH: a diner searches by LOCATION + DATE/TIME + PARTY SIZE; the system finds restaurants that have an AVAILABLE table matching the party size at (or near) the requested time — a geo + availability query (read-optimized, like the Airbnb search side). BOOKING: when the diner books a slot, the system performs an ATOMIC reservation — atomically mark the specific table/slot RESERVED only if it's currently AVAILABLE (a per-slot lock / conditional update / transaction — the booking pattern), so two concurrent diners can NEVER both reserve the same table at the same time (no double-booking); strongly consistent (reservations are the source of truth). A short HOLD during checkout (if needed) -> confirm. Availability updates so the slot no longer shows as open. Around this: CANCELLATIONS (free the slot), REMINDERS (reduce no-shows), WAITLISTS, and an OVERBOOKING strategy (since no-shows happen, restaurants may accept slightly more than capacity — carefully). Restaurant-side tools manage tables/availability. Trace it: diner searches 'table for 4, 7pm Sat, downtown' -> availability search returns restaurants with a matching open slot -> diner books -> atomic reserve (table free? yes -> reserved) -> confirm + reminder; a concurrent booker for the same table fails. Availability search over table/slot inventory + atomic no-double-booking reservation + reminders/cancellations is the shape."),
      K("api", "API / flow",
        "search: location + date/time + party size -> restaurants with an available matching table/slot\nbook: POST reservation { restaurant, table/slot, party, time } ->\n  atomically reserve the slot IFF available (lock/conditional update/transaction) -> no double-booking\n  else 'slot taken' (pick another)\nmanage: cancel (free slot) ; reminders (reduce no-shows) ; waitlist ; overbooking strategy\ninventory: per-restaurant tables x time-slots availability calendar (real-time)"),
      K("data_model", "Data model",
        "restaurants: location, tables (capacities), hours, turn times\nslots/inventory: (restaurant, table, time-slot) -> status available | reserved -> the booking truth\n  unique/overlap constraint per table-slot prevents double-booking\nreservations: party, time, table/slot, status (held/confirmed/cancelled)\navailability: derived from inventory - reservations (real-time, searchable)\nsearch index: restaurants by location + availability (read-optimized)"),
      C("deep_dive", "Deep dive: preventing double-booking (atomic slot reservation)",
        "The correctness core is identical to the booking pattern (Airbnb/ticketing): a specific TABLE at a specific TIME can be reserved by exactly ONE party, and the naive approach FAILS. THE RACE: 'check if table T at 7pm is available; if so, book it' has a race — two diners both read the slot as AVAILABLE and both book it -> DOUBLE-BOOKING (two parties show up for one table — a real-world disaster). THE FIX — atomic reservation: make the check-and-reserve ATOMIC — atomically mark the table-slot RESERVED only if it's currently AVAILABLE, as ONE indivisible operation, so concurrent attempts SERIALIZE and only the FIRST succeeds. Implementations (same as the booking designs): (1) a per-slot CONDITIONAL UPDATE — 'UPDATE slot SET status=reserved WHERE id=? AND status=available' — 0 rows affected means someone got it first; (2) a TRANSACTION with the slot row LOCKED (check no conflicting reservation, then insert); or (3) a UNIQUE/exclusion constraint on (restaurant, table, time-slot) so a conflicting insert fails atomically. The reservation is STRONGLY CONSISTENT (the source of truth for who has the table). HOLDS: if checkout/confirmation takes time, place a short HOLD (slot blocked during booking) -> confirm -> release on timeout (reserve-then-confirm), though restaurant bookings are often quick/instant. The inventory unit is a TABLE-SLOT (a specific table for a dining window/turn time), and availability accounts for table CAPACITY (match party size) and TURN TIME (a table is occupied for the dining duration, freeing for the next slot). So an atomic check-and-reserve on the specific table-slot (no double-booking, strongly consistent) — the booking pattern — is the correctness core interviewers probe (recognizing it's the same atomic-reservation problem as Airbnb/ticketing, applied to tables)."),
      C("deep_dive", "Deep dive: availability search, inventory & domain concerns",
        "The other half is AVAILABILITY SEARCH over table/slot inventory, plus restaurant-specific domain concerns. AVAILABILITY SEARCH: diners search by LOCATION (nearby restaurants — a geo query, the proximity pattern), DATE/TIME, and PARTY SIZE, and the system returns restaurants that have an AVAILABLE table matching the party size at (or near — suggest nearby times) the requested slot — combining geo search + availability filtering over each restaurant's table-slot inventory minus existing reservations. Like Airbnb, this read-heavy search can be served from a read-optimized/denormalized store (eventually consistent — a slot might briefly show available after being booked) BECAUSE the booking step re-checks atomically (search is discovery; booking is the authority). INVENTORY MODEL: a restaurant's bookable inventory is TABLES (each with a CAPACITY) across TIME SLOTS, where a reservation occupies a table for a TURN TIME (dining duration), after which it's free for the next party — so availability is computed per table-slot, matching party size to table capacity (and possibly combining tables for large parties), within the restaurant's hours/policies. DOMAIN CONCERNS (restaurant-specific): NO-SHOWS are common (a reserved party doesn't arrive), wasting capacity — so restaurants use REMINDERS (reduce no-shows), sometimes deposits/cancellation policies, and OVERBOOKING strategies (accept slightly MORE reservations than tables, betting on no-shows — like airlines — to maximize utilization, carefully balanced against the cost of turning away an over-booked party); WAITLISTS (for fully-booked times / walk-ins); CANCELLATIONS (free the slot, ideally re-offered to the waitlist); and table MANAGEMENT (the host seats parties, handles combining tables, walk-ins). RESTAURANT-SIDE: tools for restaurants to manage their tables, availability, hours, and reservations (a two-sided system). So availability search (geo + time + party over table-slot inventory, read-optimized) + the table/turn-time inventory model + domain handling (no-shows/overbooking/waitlists/reminders) is the search/domain core interviewers probe (the table+turn-time inventory and overbooking are the restaurant-specific twists on the generic booking pattern)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "DOUBLE-BOOKING is the cardinal risk — atomic check-and-reserve on the table-slot (strongly consistent); never check-then-book. AVAILABILITY SEARCH (read-heavy) — geo + time + party over inventory -> read-optimized/denormalized + cached; eventual-consistency OK (booking re-checks). POPULAR SLOTS contention (prime Saturday 7pm) — concurrent bookers for the same table -> atomic reserve serializes (one wins). NO-SHOWS — wasted capacity -> reminders + overbooking + deposits/cancellation policies. INVENTORY accuracy — table capacity + turn times -> correct slot computation. Trade-offs: atomic reservation (no double-booking, strongly consistent — brief contention on hot slots) vs check-then-book (races -> double-booking); read-optimized eventually-consistent search (fast, scalable — may show a just-booked slot, fine since booking re-checks) vs querying the transactional store (consistent — slow); overbooking (higher utilization vs no-shows — risk of over-capacity / turning away a booked party) vs exact (no risk — empty tables from no-shows); reminders/deposits (reduce no-shows — friction) vs none; reserve-with-hold (no double-book during confirm — manage holds) vs instant-confirm (simple — fine for quick bookings). Closing signal: the booking pattern applied to restaurant tables — availability SEARCH (geo + date/time + party size over a table-slot inventory model with turn times, read-optimized) + an ATOMIC table-slot RESERVATION (no double-booking, strongly consistent), plus domain handling for no-shows (reminders, overbooking, deposits), waitlists, and cancellations — so diners find and book tables and no table is ever double-booked."),
      C("deep_dive", "Deep dive: table management, two-sided, integrations & operations",
        "Operationally a reservation system is a two-sided marketplace (diners + restaurants) built on the booking pattern. Table management (restaurant side): restaurants configure their floor (tables + capacities), hours, turn times, and which inventory is bookable online vs held for walk-ins; a host/POS interface manages the live floor (seat parties, combine/split tables, handle walk-ins + waitlist) — the reservation system integrates with this so online + in-person reservations share one consistent inventory (avoiding double-booking across channels). Availability computation: derive bookable slots from tables × time × turn-time − existing reservations − held inventory, matching party size (and table-combining for large parties); real-time + consistent. Search & discovery: diners search by location/cuisine/time/party (geo + availability — proximity + search patterns) + browse, reviews/ratings, and recommendations; show alternative times if exact isn't available. No-show mitigation: reminders (SMS/email), cancellation policies, deposits/credit-card holds for prime times, and overbooking (carefully). Waitlist + notify: join a waitlist; notify when a slot frees (from a cancellation). Reservation lifecycle: held/confirmed/seated/completed/cancelled/no-show — a state machine + reminders. Two-sided: restaurant tools (manage availability, view/manage reservations, guest profiles/preferences) + diner app (search/book/manage); restaurant onboarding. Integrations: POS, waitlist apps, and (for paid bookings/deposits) payments. Scale: reads (search) >> writes (bookings) -> read-optimized search + caching; bookings strongly consistent; shard by restaurant/region. Special events: prime times + popular restaurants are high-contention (atomic reserve handles it); ticketed events (prix-fixe) blend with ticket-booking. Observability: search latency, booking success/double-booking incidents (must be 0), no-show rate, availability freshness, and waitlist conversion are the SLOs. The spine holds: table-slot inventory (capacity + turn time) + availability search (geo/time/party, read-optimized) + atomic no-double-booking reservation + no-show/overbooking/waitlist handling, two-sided + channel-consistent."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you prevent two diners booking the same table?' atomic check-and-reserve on the specific table-slot — 'reserve IFF available' as one atomic operation (conditional update/lock/transaction) — so concurrent bookers serialize and only one wins; never check-then-book (it races). 'Same pattern as...?' yes — the booking pattern (Airbnb/ticketing) applied to restaurant tables. 'Availability search?' geo (location) + date/time + party size over the restaurant's table-slot inventory (read-optimized, eventually consistent — fine because booking re-checks atomically); suggest nearby times. 'Inventory model?' tables (with capacities) × time slots, where a reservation occupies a table for a TURN TIME (dining duration), then frees for the next party; match party size to table capacity. 'No-shows?' reminders, cancellation policies/deposits, and OVERBOOKING (accept slightly more than capacity, betting on no-shows — like airlines, carefully) + waitlists. 'Online + walk-in double-booking?' integrate with the restaurant's host/POS so all channels share one consistent inventory. 'Popular slot contention (prime Saturday)?' atomic reserve serializes concurrent bookers. 'Cancellation?' frees the slot (re-offer to waitlist). 'Two-sided?' diner app + restaurant management tools. Each returns to the spine: table-slot inventory (capacity/turn-time) + availability search + atomic no-double-booking reservation + no-show/overbooking/waitlist handling."),
    ],
    "Restaurant reservation tests the BOOKING pattern applied to tables: availability SEARCH (geo + date/time + party size over a table-slot inventory model with capacities + turn times, read-optimized) and an ATOMIC table-slot RESERVATION ('reserve IFF available' via conditional update/lock/transaction — no double-booking, strongly consistent), plus restaurant-specific domain handling (no-shows → reminders/overbooking/deposits, waitlists, cancellations) and channel-consistent inventory (online + walk-in). The signal is atomic no-double-booking + availability search (the booking pattern) + no-show/overbooking handling, not a check-then-book flow.",
    [
      G("check_then_book", "Checking a table is free, then booking it in separate steps.", "Make 'reserve IFF available' a single atomic operation (conditional update/lock/transaction) — concurrent diners serialize, one wins; the booking pattern.", "Reads slot availability then inserts a reservation; two diners double-book the same table-slot."),
      G("ignore_turn_time", "Modeling inventory without table capacity / turn times.", "Model inventory as tables (capacities) × time slots with turn times; match party size; compute availability per table-slot.", "Treats a restaurant as a single capacity number; can't match party size or handle dining-window occupancy."),
      G("ignore_noshows", "Ignoring no-shows / channel consistency.", "Mitigate no-shows (reminders, overbooking, deposits, waitlists) and share one consistent inventory across online + walk-in (host/POS).", "No no-show handling (wasted tables) and separate online vs in-person inventory (double-booking across channels)."),
    ],
    0.5, DIAG.reservation, "Restaurant reservation architecture"),

  // ─────────────────── HELPDESK / TICKETING (ZENDESK) ───────────────────────
  TT("sysd_m21", "sysd_m21_t2", 2, "Design a Helpdesk / Ticketing System (Zendesk)", "design-helpdesk-ticketing",
    ["case-study", "workflow", "state-machine", "routing"],
    "Customers fire support requests at you from email, chat, and the web; each becomes a ticket that must reach the right agent, move through a lifecycle (open → resolved → closed), respect SLA deadlines, and carry the whole conversation — across thousands of agents and millions of tickets. How do you build a helpdesk/ticketing system?",
    "A TICKET is a support request with a STATE/lifecycle (open → assigned → pending → resolved → closed); the system ROUTES/assigns tickets to agents (by skill, queue, load), tracks SLA deadlines (with escalation), carries the conversation thread, and layers automation (auto-responses, macros) + a knowledge base. It's a workflow/state-machine + routing + SLA system. Ticket lifecycle/state + routing, plus SLA tracking/automation/scale, are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: customers SUBMIT support requests (TICKETS) via multiple channels (email, chat, web form); ROUTE/ASSIGN tickets to agents; track ticket STATE through its lifecycle (open → in-progress → resolved → closed); hold the CONVERSATION (customer ↔ agent messages); track SLAs (response/resolution deadlines); knowledge base + automation; reporting. Non-functional: reliable WORKFLOW/state management (tickets move correctly through their lifecycle), good ROUTING/assignment (right agent, balanced load), SLA tracking (meet deadlines, escalate), SCALE (many tickets/agents), and multichannel. Clarify scope: a customer-support helpdesk / ticketing system (Zendesk / Freshdesk / ServiceNow style). The defining characteristics: (1) a TICKET has a LIFECYCLE / STATE MACHINE — it moves through states (new → open/assigned → pending → resolved → closed, with reopens) via well-defined transitions, so the core is modeling + managing this WORKFLOW/state; (2) ROUTING / ASSIGNMENT — incoming tickets must reach the RIGHT agent (by skill/team/queue) with balanced LOAD (don't overload one agent), automatically or via queues; and (3) SLA TRACKING — tickets have service-level deadlines (e.g. respond within 1h, resolve within 24h) that must be tracked, with ESCALATION when at risk/breached. Plus the CONVERSATION thread, AUTOMATION (auto-responses, macros, triggers), a knowledge base, and reporting. It's essentially a WORKFLOW/state-machine + a routing/queueing system + SLA timers. So the design centers on the ticket lifecycle/state + routing/assignment + SLA tracking/automation."),
      K("estimation", "Capacity estimation (with numbers)",
        "Tickets: many (millions over time), from multiple channels (email/chat/web) -> normalized to tickets.\nState: each ticket = a state machine (new->open->pending->resolved->closed, reopen).\nRouting: assign to agents by skill/team/queue + load balancing (don't overload).\nSLA: per-ticket deadlines (response/resolution) -> timers + escalation when at risk/breached.\nAgents: thousands ; conversation thread per ticket ; automation (macros/triggers/auto-reply).\nTakeaway: ticket state machine + routing/assignment (skill/load) + SLA tracking/escalation +\nconversation + automation + KB -> a workflow + queueing + SLA system."),
      C("hld", "High-level design",
        "A TICKET is created from any CHANNEL (email parsed into a ticket, chat, web form, API) — normalized into a ticket with a CONVERSATION thread (all customer ↔ agent messages), metadata (priority, category, customer), and a STATE. The ticket moves through a LIFECYCLE / STATE MACHINE — new → open/assigned → pending (waiting on customer/3rd party) → resolved → closed (+ reopen) — via defined transitions. ROUTING/ASSIGNMENT: incoming tickets are routed to the right AGENT or QUEUE — by SKILL/team (technical vs billing), category, and LOAD (balance across available agents — round-robin/least-loaded, or agents pull from queues) — automatically (rules) and/or manually. SLA TRACKING: each ticket has SLA targets (first-response time, resolution time, by priority); the system tracks these with TIMERS, ESCALATING (notify, reassign, raise priority) when an SLA is at risk or BREACHED. AUTOMATION: triggers/rules (auto-acknowledge, auto-route, auto-tag), MACROS (canned responses/actions agents apply), and a KNOWLEDGE BASE (self-service articles + suggested answers to deflect tickets). REPORTING/analytics (volumes, resolution times, SLA compliance, agent performance). Trace it: customer emails support -> a ticket is created (state: new) -> auto-routed to the billing queue (skill) + auto-acknowledged -> assigned to an agent (load-balanced) -> agent converses + resolves -> SLA timer tracked/escalated if at risk -> resolved → closed. Ticket state machine + routing/assignment (skill/load) + SLA tracking/escalation + conversation + automation/KB is the shape."),
      K("api", "API / flow",
        "create: channel (email/chat/web/API) -> ticket { conversation, priority, category, state: new }\nroute/assign: by skill/team/queue + load balancing -> agent (rules or pull)\nlifecycle: state machine (new->open->pending->resolved->closed, reopen) via transitions\nSLA: per-ticket targets (first-response/resolution by priority) -> timers -> escalate (at risk/breach)\nautomation: triggers (auto-route/tag/reply) + macros (canned responses) + knowledge base\nconverse: customer<->agent messages on the ticket ; report (volumes/SLA/agent metrics)"),
      K("data_model", "Data model",
        "tickets: id, customer, channel, priority, category, STATE, assignee, SLA targets, conversation\nstate machine: states + allowed transitions (new/open/pending/resolved/closed + reopen)\nrouting: rules + queues + agent skills/availability/load -> assignment\nSLA: deadlines (first-response/resolution) + timers + escalation state\nautomation: triggers/rules + macros ; knowledge base articles\nagents/teams: skills, availability, load"),
      C("deep_dive", "Deep dive: ticket lifecycle (state machine) & routing/assignment",
        "The core is modeling the ticket WORKFLOW and getting tickets to the right agent. TICKET STATE MACHINE: a ticket isn't just a message — it has a LIFECYCLE with well-defined STATES and TRANSITIONS: NEW (just created) → OPEN/assigned (an agent is working it) → PENDING (waiting on the customer or a third party) → RESOLVED (agent believes it's solved) → CLOSED (finalized), with REOPEN (customer responds after resolution) and escalation/on-hold states. Modeling this as a STATE MACHINE (defined transitions, who can move it, what each state means) is the backbone — it drives the agent workflow, SLA timers (which pause in 'pending'), automation, and reporting; transitions are auditable. ROUTING / ASSIGNMENT: incoming tickets must reach the RIGHT agent, which combines: (1) SKILL/team-based routing — route a billing question to the billing team, a technical issue to engineers (by category/skill matching), so the agent can actually handle it; (2) QUEUES — tickets land in team/skill queues that agents PULL from, or are PUSHED/assigned; (3) LOAD BALANCING — distribute tickets across available agents so none is overloaded and others idle (round-robin, least-busy, or capacity-based — considering each agent's current open-ticket load + availability/online status); and (4) PRIORITY — urgent/high-priority tickets (or VIP customers) routed/handled first. Routing is driven by RULES (auto-route by category/keywords/customer) + manual assignment, and is dynamic (re-route on escalation, agent unavailability). Getting the right agent (skill) with balanced load is key to efficient support. So a ticket STATE MACHINE (lifecycle/transitions) + skill-and-load-based ROUTING/assignment (queues, rules, priority) is the workflow core interviewers probe (a ticketing system is fundamentally a workflow/state-machine + a routing/queueing system)."),
      C("deep_dive", "Deep dive: SLA tracking, automation, conversation & scale",
        "Around the lifecycle + routing sit SLAs, automation, the conversation, and scale. SLA TRACKING (a defining feature): support tickets have SERVICE-LEVEL targets — e.g. first RESPONSE within 1 hour, RESOLUTION within 24 hours, varying by PRIORITY/customer tier — and the system must TRACK these against each ticket with TIMERS, computing time elapsed (PAUSING during 'pending'/waiting-on-customer states, business-hours-aware), and ESCALATING when an SLA is AT RISK or BREACHED — notify the agent/manager, raise priority, or reassign — so commitments are met. SLA tracking + escalation is core (it's what makes it a 'service' desk, not just an inbox). AUTOMATION: reduce manual work + speed resolution — TRIGGERS/rules (auto-acknowledge on creation, auto-route by category, auto-tag, auto-escalate), MACROS (canned responses/action bundles agents apply with one click), SLA-based automations, and increasingly AI (suggested replies, auto-categorization, chatbots/auto-resolution). KNOWLEDGE BASE: self-service articles (deflect tickets — customers solve their own issues) + suggested KB answers to agents/customers. CONVERSATION: each ticket holds the full threaded CONVERSATION (customer ↔ agent, public replies + internal notes) across channels, so context is preserved as the ticket moves between agents/states (omnichannel — email, chat, social all into one ticket thread). REPORTING/ANALYTICS: volumes, resolution times, SLA compliance, CSAT, agent performance — for managing the support operation. SCALE: many tickets + agents -> the system scales (ticket store, routing, search over tickets), shard by org/account (multi-tenant SaaS — the multi-tenant pattern: isolate each customer company's helpdesk). MULTI-TENANCY: it's a SaaS serving many companies, each with their own agents/tickets/config — isolated. So SLA timers + escalation + automation (triggers/macros/KB/AI) + the omnichannel conversation thread + multi-tenant scale is the operational core interviewers probe (SLA tracking and automation are what distinguish a helpdesk from a shared inbox)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "ROUTING/ASSIGNMENT — right agent (skill) + balanced load -> rules + queues + load balancing; mis-routing wastes time. SLA TRACKING — per-ticket timers (business-hours, pausing) + escalation at scale -> a timer/scheduling system; breaches are the failure. AGENT LOAD BALANCING — avoid overload/idle -> capacity-based assignment. STATE CORRECTNESS — tickets must move through valid transitions -> a state machine. SCALE / MULTI-TENANCY -> shard by org; isolate tenants. CHANNEL NORMALIZATION — email/chat/social into one ticket model. Trade-offs: push assignment (agents get assigned tickets — load-balanced control) vs pull/queues (agents take next — self-pacing, simple — risk of cherry-picking); skill-based routing (right agent — needs skill modeling) vs round-robin (simple — wrong-agent handoffs); strict SLA timers + escalation (meet commitments — complexity: pausing/business-hours) vs none (simple — missed SLAs); heavy automation/macros/KB (efficiency, deflection — setup effort) vs manual (flexible — slow/costly); state machine (correct lifecycle, auditable — rigidity) vs free-form statuses (flexible — inconsistent). Closing signal: model the ticket as a STATE MACHINE (lifecycle/transitions), ROUTE/assign to the right agent by skill + balanced load (queues/rules/priority), TRACK SLAs with timers + escalation, hold the omnichannel CONVERSATION, and layer automation (triggers/macros/AI) + a knowledge base — a multi-tenant workflow + queueing + SLA system that gets support requests to the right agent and resolved within commitments."),
      C("deep_dive", "Deep dive: omnichannel, automation/AI, multi-tenancy & operations",
        "Operationally a helpdesk is a multi-tenant SaaS workflow platform. Omnichannel ingestion: tickets come from EMAIL (parse inbound email -> ticket, thread replies back), CHAT/messaging (live chat -> ticket), WEB forms, social media, phone (call logs), and API — all NORMALIZED into a unified ticket with one conversation thread, so an agent has full context regardless of channel; replies go back out on the original channel. Routing engine: skill/team-based routing, round-robin/load-balanced/capacity-based assignment, business-rules (auto-route by keywords/category/customer), priority + VIP handling, and re-routing on escalation/unavailability; agents have skills, availability (online/away), and a load (concurrent-ticket limit). SLA management: configurable SLA policies (per priority/tier), business-hours/holiday calendars, pausing during pending states, escalation rules (notify/reassign/raise priority at thresholds), and breach reporting. Automation & AI: triggers/automations (event-driven rules), macros (canned multi-action responses), auto-categorization/tagging, AI-suggested replies + summaries, and chatbots/virtual agents that auto-resolve or deflect (with the knowledge base) — increasingly central to scaling support. Knowledge base / self-service: a searchable help center (deflects tickets) + suggested articles to agents/customers; community forums. Collaboration: internal notes, @mentions, ticket sharing, side conversations, and linked/merged/parent-child tickets. Reporting & ops: volumes, first-response/resolution times, SLA compliance, CSAT, agent performance, and forecasting — to run the support org. Multi-tenancy: it's SaaS serving many companies, each with isolated tickets/agents/config/branding (the multi-tenant-SaaS design) — shard by org, isolate data. Integrations: CRM (customer context), e-commerce, dev tools (link tickets to bugs). Scale: ticket store + search (over tickets/conversations) + routing + automation scale; sharded by tenant. Observability: ticket volumes, routing/assignment time, SLA compliance + breaches, automation deflection, and agent load are the SLOs. The spine holds: omnichannel tickets -> state-machine lifecycle + skill/load routing + SLA timers/escalation + conversation + automation/AI/KB, multi-tenant + integrated."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'What's a ticket fundamentally?' a support request modeled as a STATE MACHINE — new → open/assigned → pending → resolved → closed (+ reopen) — with defined transitions driving the agent workflow, SLA timers, automation, and reporting. 'How do tickets reach the right agent?' ROUTING/assignment by SKILL/team (billing vs technical) + LOAD balancing (don't overload an agent — round-robin/least-busy/capacity) + priority, via rules + queues (push or pull). 'SLAs?' per-ticket targets (first-response/resolution by priority/tier) tracked with timers (business-hours-aware, paused in 'pending'), escalating (notify/reassign/raise priority) when at risk/breached — what makes it a service desk. 'Reduce agent workload?' automation — triggers (auto-route/tag/reply), macros (canned responses), AI (suggested replies, auto-categorization, chatbots), and a knowledge base (self-service deflection). 'Multiple channels?' normalize email/chat/web/social into one ticket + conversation thread (omnichannel); reply back on the channel. 'Context as it moves between agents?' the full conversation thread + internal notes travel with the ticket. 'Scale / many companies?' it's multi-tenant SaaS — isolate each company's tickets/agents/config, shard by org. 'Reporting?' volumes, resolution times, SLA compliance, CSAT, agent metrics. 'Reopen?' state transition (resolved → open) when the customer replies. Each returns to the spine: ticket state machine + skill/load routing + SLA timers/escalation + omnichannel conversation + automation/AI/KB, multi-tenant."),
    ],
    "A helpdesk/ticketing system tests modeling a ticket as a STATE MACHINE (lifecycle/transitions: new→open→pending→resolved→closed +reopen), ROUTING/assigning to the right agent by SKILL + balanced LOAD (queues/rules/priority), tracking SLAs with timers + escalation (business-hours-aware, paused in pending), holding the omnichannel CONVERSATION, and layering automation (triggers/macros/AI) + a knowledge base — as a multi-tenant workflow + queueing + SLA system. The signal is ticket-state-machine + skill/load routing + SLA tracking/automation, not a shared inbox.",
    [
      G("no_state_machine", "Treating tickets as flat messages with no lifecycle/state machine.", "Model the ticket as a state machine (new→open→pending→resolved→closed +reopen) with defined transitions driving workflow/SLA/automation.", "Tickets are just messages with an ad-hoc 'status' string; lifecycle/transitions undefined."),
      G("no_skill_load_routing", "Assigning tickets arbitrarily (no skill matching or load balancing).", "Route by skill/team + balance load (queues/rules/capacity) + priority — the right agent, not overloaded.", "Round-robins to anyone / piles onto one agent; wrong-agent handoffs + overload."),
      G("no_sla_tracking", "Not tracking SLA deadlines/escalation.", "Track per-ticket SLA timers (business-hours-aware, paused in pending) and escalate at risk/breach — what makes it a service desk.", "No response/resolution deadlines or escalation; SLAs silently missed."),
    ],
    0.4, DIAG.helpdesk, "Helpdesk / ticketing architecture"),
];

// ── 3 exercises per topic ────────────────────────────────────────────────────
const xpFor = (l) => (l === "warmup" ? 5 : l === "easy" ? 10 : l === "medium" ? 15 : 20);
const diffFor = (l) => (l === "warmup" ? 0.1 : l === "easy" ? 0.2 : l === "medium" ? 0.4 : 0.6);
function pm(moduleId, o) {
  return { trackKey: TRACK_KEY, moduleId, topicId: o.topicId, exerciseId: o.exerciseId,
    position: o.position, level: o.level, type: "pattern_match", title: o.title, scenario: o.scenario,
    instructions: "Pick the best answer.", starterCode: "", expectedSolution: o.correct,
    blanks: [{ options: o.options }], testCases: [{ type: "pattern_match", correct: o.correct, explanation: o.explanation }],
    hints: [], xpReward: xpFor(o.level), difficulty: diffFor(o.level) };
}

